head.script:
scwin.districtCd = "";
scwin.rowFlag = "";

scwin.onpageload = function() {
    let memJson = $c.data.getMemInfo();
    console.log(memJson);
    scwin.districtCd = memJson.districtCd;     // 권역

    const codeOptions = [
        { grpCd : "OP256", compID : "lc_basisSalStd,lc_saturdayBasisSalStd,lc_extdSalStd,lc_saturdayExtdSalStd,lc_midngtSalStd,lc_saturdayMidngtSalStd"}
    ];
    $c.data.setCommonCode(codeOptions, scwin.f_init);

    const codeOptions2 = [ 
        {
            method: "getLuxeComboData", 
            param1: "GoodsSurchargeWorkStepEBC", 
            param2: "retriveDistrictCodeList",
            //param3: ["CMP"],
            compID: "lc_con_districtCd, gr_retrieveResult:districtCd" 
        }
    ];
    $c.data.setGauceUtil(codeOptions2);

    oDiv1_1.setStyle("display", "block");
    oDiv1_2.setStyle("display", "none");
    oDiv1_3.setStyle("display", "block");
    oDiv1_4.setStyle("display", "none");

    oDiv2_1.setStyle("display", "block");
    oDiv2_2.setStyle("display", "none");
    oDiv2_3.setStyle("display", "block");
    oDiv2_4.setStyle("display", "none");

    lc_con_districtCd.setSelectedIndex(0);
    var districtCd = scwin.districtCd;
    lc_con_districtCd.setValue(districtCd);

    $c.gus.cfDisableObjects([btn_Add,btn_Update, btn_Save, con_main, table1, table2]);

    //scwin.f_init();
};

scwin.f_init = function () {

    lc_hhEchYn.setSelectedIndex(0);

    lc_workStHh.setSelectedIndex(0);
    lc_workEndHh.setSelectedIndex(0);
    lc_basisSalStd.setSelectedIndex(1);
    lc_extdStHh.setSelectedIndex(0);
    lc_extdEndHh.setSelectedIndex(0);
    lc_extdSalStd.setSelectedIndex(4);
    lc_midngtStHh.setSelectedIndex(0);
    lc_midngtEndHh.setSelectedIndex(0);
    lc_midngtSalStd.setSelectedIndex(1);

    lc_saturdayWorkStHh.setSelectedIndex(0);
    lc_saturdayWorkEndHh.setSelectedIndex(0);
    lc_saturdayBasisSalStd.setSelectedIndex(1);
    lc_saturdayExtdSalStd.setSelectedIndex(4);
    lc_saturdayExtdEndHh.setSelectedIndex(0);
    lc_saturdayMidngtStHh.setSelectedIndex(0);
    lc_saturdayMidngtEndHh.setSelectedIndex(0);
    lc_saturdayMidngtSalStd.setSelectedIndex(1);
    lc_saturdayExtdStHh.setSelectedIndex(0);

    lc_dnrStHh.setSelectedIndex(0);
    lc_dnrEndHh.setSelectedIndex(0);
    lc_sprStHh.setSelectedIndex(0);
    lc_sprEndHh.setSelectedIndex(0);
    lc_breakfastStHh.setSelectedIndex(0);
    lc_breakfastEndHh.setSelectedIndex(0);

    lc_lunchStHh.setSelectedIndex(0);
    lc_lunchEndHh.setSelectedIndex(0);

    lc_nextDdBreakfastStHh.setSelectedIndex(0);
    lc_nextDdBreakfastEndHh.setSelectedIndex(0);
}

scwin.f_AddRow = async function(){

//        if(ds_retrieveResult.getRowCount() == 0)  f_createHeader(1);

    var chk = await scwin.f_checkEndDate();
    if(!chk) return;

    ds_retrieveResult.insertRow();
    gr_retrieveResult.setFocusedCell(ds_retrieveResult.getRowCount()-1, 0);
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "districtCd"           , lc_con_districtCd.getValue());
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "adptStDt"             , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "adptEndDt"            , "99999999");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "wageAgrmntDt"         , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "pyDdBasisAmt"         , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "chiefFixedSal"        , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "crewsFixedSal"        , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "hhEchYn"              , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "workStHh"             , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "workEndHh"            , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "basisSalStd"          , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "basisSalAdptRt"       , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "extdStHh"             , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "extdEndHh"            , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "extdSalStd"           , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "extdSalRt"            , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "midngtStHh"           , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "midngtEndHh"          , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "midngtSalStd"         , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "midngtSalRt"          , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "dnrStHh"              , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "dnrEndHh"             , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "dnrHhAdptYn"          , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "dnrAmt"               , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "dnrAmtPayYnCu"        , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "dnrAmtPayYnDuse"      , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "sprStHh"              , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "sprEndHh"             , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "sprHhAdptYn"          , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "sprAmt"               , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "sprAmtPayYnCu"        , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "sprAmtPayYnDuse"      , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "breakfastStHh"        , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "breakfastEndHh"       , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "breakfastHhAdptYn"    , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "breakfastAmt"         , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "breakfastAmtPayYnCu"  , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "breakfastAmtPayYnDuse", "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "secTableAmtStd"       , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "lunchStHh"            , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "lunchEndHh"           , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "lunchHhAdptYn"        , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "lunchAmt"             , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "lunchAmtPayYnCu"      , "");
    ds_retrieveResult.setCellData( ds_retrieveResult.getRowPosition(),  "lunchAmtPayYnDuse"    , "");

    $c.gus.cfEnableObjects([btn_Add,btn_Update, btn_Save]);
    $c.gus.cfDisableObjects([lc_basisSalStd,lc_saturdayBasisSalStd,lc_extdSalStd,lc_saturdayExtdSalStd,lc_midngtSalStd,lc_saturdayMidngtSalStd]);

    scwin.f_init();
    scwin.f_RowChange();
}

