scwin.f_Retrieve = function () {

//        if(!cfValidate([con_table])) return;
/*
    var strAtcion = "/ds.op.adjmbd.wageadjmproc.RetrieveStevedoringWagesWorkStandardCMD.do";

    tr_retrieve.Action = strAtcion;
    tr_retrieve.Post();
*/
    $c.sbm.execute(sbm_retrieve);
    $c.gus.cfEnableObjects([btn_Add]);

    //var rows = ds_retrieveResult.getRowCount();
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function (){

    if(!await scwin.f_basicMoney()) {
        console.log("await scwin.f_basicMoney()");
        return;
    }

    if(!$c.gus.cfValidate([main_table])) {
        console.log("main_table");
        return;
    }

    if(!await scwin.f_checkDate())  {
        console.log("await scwin.f_checkDate()");
        return;
    }
    if(!await scwin.f_checkTime())  {
        console.log("await scwin.f_checkTime()");
        return;
    }

    if( ds_retrieveResult.getModifiedIndex().length == 0 ){
        $c.win.alert("변경된 사항이 없습니다.");
    }else if(await $c.win.confirm("저장하시겠습니까?")){
        //tr_save.Post();
        $c.sbm.execute(sbm_save);
        $c.gus.cfEnableBtnOnly([btn_Add, btn_Update]);
    }
}

