//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Modify = function () {
    $c.gus.cfEnableObjects([con_main, table1, table2]);
    $c.gus.cfEnableBtnOnly([btn_Add, btn_Save]);
    $c.gus.cfDisableObjects([lc_basisSalStd,lc_saturdayBasisSalStd,lc_extdSalStd,lc_saturdayExtdSalStd,lc_midngtSalStd,lc_saturdayMidngtSalStd]);
    $c.gus.cfDisableObjects([ica_adptStDt, ica_wageAgrmntDt]);
}

//-------------------------------------------------------------------------
// 조회 조건 초기화
//-------------------------------------------------------------------------
scwin.f_FieldClear = function (){
    ica_con_wageAgrmntDt.setValue("");
    ica_con_adptDt.setValue("");
    var districtCd = scwin.districtCd;
    lc_con_districtCd.setValue(districtCd);
}

scwin.f_basicMoney = function () {
    var value = ed_pyDdBasisAmt.getValue();
    if ( value == "0" || value == "" ) {
        $c.win.alert("평일기본금액은 필수 입력 항목입니다.");
        ed_pyDdBasisAmt.focus();
        return false;
    }
    return true;
}

scwin.f_checkDate = async function () {

    var adptStDt  = ds_retrieveResult.getCellData(ds_retrieveResult.getRowCount()-1,"adptStDt");
    var adptEndDt = ds_retrieveResult.getCellData(ds_retrieveResult.getRowCount()-1,"adptEndDt");

    if ( adptEndDt != "99999999" ) {
        if (! await $c.gus.cfIsAfterDate(adptStDt, adptEndDt, false)) {
            //$c.win.alert(adptStDt+"    "+adptEndDt);
            $c.win.alert("적용종료일을 적용시작일보다 이후로 입력하십시오.");
            ds_retrieveResult.setCellData(row,"adptEndDt", "99999999");
            return false;
        }
    }
    return true;
}


scwin.f_checkTime =  async function () {

    var row       = ds_retrieveResult.getRowCount();
    var adptStDt  = ds_retrieveResult.getCellData(ds_retrieveResult.getRowCount(),"adptStDt");

    var timeYn    = lc_hhEchYn.getValue();

    for (var i=0; i < row; i++) {

        var workStHh             = adptStDt+ds_retrieveResult.getCellData(i,"workStHh"            )+"00";   //근무시작시간
        var workEndHh            = adptStDt+ds_retrieveResult.getCellData(i,"workEndHh"           )+"00";   //근무종료시간
        var saturdayWorkStHh     = adptStDt+ds_retrieveResult.getCellData(i,"saturdayWorkStHh"    )+"00";   //토요일근무시작시간
        var saturdayWorkEndHh    = adptStDt+ds_retrieveResult.getCellData(i,"saturdayWorkEndHh"   )+"00";   //토요일근무종료시간

        var extdStHh             = adptStDt+ds_retrieveResult.getCellData(i,"extdStHh"            )+"00";   //연장시작시간
        var extdEndHh            = adptStDt+ds_retrieveResult.getCellData(i,"extdEndHh"           )+"00";   //연장종료시간
        var saturdayExtdStHh     = adptStDt+ds_retrieveResult.getCellData(i,"saturdayExtdStHh"    )+"00";   //토요일연장시작시간
        var saturdayExtdEndHh    = adptStDt+ds_retrieveResult.getCellData(i,"saturdayExtdEndHh"   )+"00";   //토요일연장종료시간

        var midngtStHh           = adptStDt+ds_retrieveResult.getCellData(i,"midngtStHh"          )+"00";   //심야시작시간
        var midngtEndHh          = adptStDt+ds_retrieveResult.getCellData(i,"midngtEndHh"         )+"00";   //심야종료시간
        var saturdayMidngtStHh   = adptStDt+ds_retrieveResult.getCellData(i,"saturdayMidngtStHh"  )+"00";   //토요일심야시작시간
        var saturdayMidngtEndHh  = adptStDt+ds_retrieveResult.getCellData(i,"saturdayMidngtEndHh" )+"00";   //토요일심야종료시간

        var dnrStHh              = adptStDt+ds_retrieveResult.getCellData(i,"dnrStHh"             )+"00";   //저녁식사시작시간
        var dnrEndHh             = adptStDt+ds_retrieveResult.getCellData(i,"dnrEndHh"            )+"00";   //저녁식사종료시간

        var sprStHh              = adptStDt+ds_retrieveResult.getCellData(i,"sprStHh"             )+"00";   //야식시작시간
        var sprEndHh             = adptStDt+ds_retrieveResult.getCellData(i,"sprEndHh"            )+"00";   //야식종료시간

        var breakfastStHh        = adptStDt+ds_retrieveResult.getCellData(i,"breakfastStHh"       )+"00";   //아침식사시작시간
        var breakfastEndHh       = adptStDt+ds_retrieveResult.getCellData(i,"breakfastEndHh"      )+"00";   //아침식사종료시간

        var nextDdBreakfastStHh  = adptStDt+ds_retrieveResult.getCellData(i,"nextDdBreakfastStHh" )+"00";   //익일아침식사시작시간
        var nextDdBreakfastEndHh = adptStDt+ds_retrieveResult.getCellData(i,"nextDdBreakfastEndHh")+"00";   //익일아침식사종료시간

        if (! await scwin.cfIsAfterTime(workStHh, workEndHh, false, i)) {
            $c.win.alert((i+1)+"번째 Row의 근무종료시간을 근무시작시간 이후로 선택하십이오.");
            lc_workEndHh.focus();
            return false;
        }
        if (! await scwin.cfIsAfterTime(saturdayWorkStHh, saturdayWorkEndHh, false, i)) {
            $c.win.alert((i+1)+"번째 Row의 토요일근무종료시간을 토요일근무시작시간 이후로 선택하십이오.");
            lc_saturdayWorkEndHh.focus();
            return false;
        }

        if ( timeYn != 1 ) {
            if (! await scwin.cfIsAfterTime(extdStHh, extdEndHh, false, i)) {
                $c.win.alert((i+1)+"번째 Row의 연장종료시간을 연장시작시간 이후로 선택하십이오.");
                lc_extdEndHh.focus();
                return false;
            }
            if (! await scwin.cfIsAfterTime(saturdayExtdStHh, saturdayExtdEndHh, false, i)) {
                $c.win.alert((i+1)+"번째 Row의 토요일연장종료시간을 토요일심야시작시간 이후로 선택하십이오.");
                lc_saturdayExtdEndHh.focus();
                return false;
            }
        }

        if (! await scwin.cfIsAfterTime(dnrStHh, dnrEndHh, false, i)) {
            $c.win.alert((i+1)+"번째 Row의 저녁식사종료시간을 저녁식사시작시간 이후로 선택하십이오.");
            lc_dnrEndHh.focus();
            return false;
        }

        if (! await scwin.cfIsAfterTime(breakfastStHh, breakfastEndHh, false, i)) {
            $c.win.alert((i+1)+"번째 Row의 아침식사종료시간을 아침식사시작시간 이후로 선택하십이오.");
            lc_breakfastEndHh.focus();
            return false;
        }

        if (! await scwin.cfIsAfterTime(nextDdBreakfastStHh, nextDdBreakfastEndHh, false, i)) {
            $c.win.alert((i+1)+"번째 Row의 익일아침식사종료시간을 익일아침식사시작시간 이후로 선택하십이오.");
            lc_nextDdBreakfastEndHh.focus();
            return false;
        }
    }
    return true;
}

scwin.cfIsAfterTime = function (startDate, endDate, exceptSameDate, i) {
    var sDate = startDate.toDate("YYYYMMDDHHMI");
    var eDate = endDate.toDate("YYYYMMDDHHMI");

    if (exceptSameDate != null && exceptSameDate == true) {
        if (sDate < eDate)
            return true;
        else
            ds_retrieveResult.setRowPosition(i);
            return false;

    } else {
        if (sDate <= eDate)
            return true;
        else
            ds_retrieveResult.setRowPosition(i);
            return false;
    }
}

//-------------------------------------------------------------------------
// 시간별여부에 따른 근무시간 타입 변경
//-------------------------------------------------------------------------
scwin.f_changeTime = function () {
    var value = lc_hhEchYn.getValue();

    if ( value == 0 ) {
        oDiv1_1.setStyle("display", "block");
        oDiv1_2.setStyle("display", "none");
        oDiv1_3.setStyle("display", "block");
        oDiv1_4.setStyle("display", "none");

        oDiv2_1.setStyle("display", "block");
        oDiv2_2.setStyle("display", "none");
        oDiv2_3.setStyle("display", "block");
        oDiv2_4.setStyle("display", "none");

    }
    else if ( value == 1 ) {
        oDiv1_1.setStyle("display", "none");
        oDiv1_2.setStyle("display", "block");
        oDiv1_3.setStyle("display", "none");
        oDiv1_4.setStyle("display", "block");


        oDiv2_1.setStyle("display", "none");
        oDiv2_2.setStyle("display", "block");
        oDiv2_3.setStyle("display", "none");
        oDiv2_4.setStyle("display", "block");

    }
}

scwin.f_OnLoadCompleted = function (rowcnt) {
    if (rowcnt > 0) {
        $c.gus.cfEnableObjects([btn_Update, btn_Save]);
    }
}

scwin.f_RowChange = function () {

    var rowstatus = ds_retrieveResult.getRowStatus(ds_retrieveResult.getRowPosition());
    var value = ds_retrieveResult.getCellData(ds_retrieveResult.getRowPosition(), "adptEndDt");

    if ( value != "99999999" ) {
        $c.gus.cfDisableObjects([btn_Update]);
    }
    else if ( value == "99999999" ) {
        $c.gus.cfEnableObjects([btn_Update]);
    }

    if ( rowstatus == "R" ) {
        $c.gus.cfDisableObjects([con_main, table1, table2]);
        $c.gus.cfDisableObjects([ica_adptStDt, ica_wageAgrmntDt]);
    } else if ( rowstatus != "R" ) {
        $c.gus.cfEnableObjects([con_main, table1, table2]);
        $c.gus.cfDisableObjects([lc_basisSalStd,lc_saturdayBasisSalStd,lc_extdSalStd,lc_saturdayExtdSalStd,lc_midngtSalStd,lc_saturdayMidngtSalStd]);
    }
}

scwin.f_checkEndDate = function () {
    var row = ds_retrieveResult.getRowCount();

    for(var i=0; i < row; i++) {
        var value = ds_retrieveResult.getCellData(i, "adptEndDt");
        if ( value == "99999999" ) {
            $c.win.alert((i+1)+"번째 적용종료 처리되지 않은 근무기준이 존재합니다.");
            return false;
        }
    }
    return true;
}

scwin.btn_fieldClear_onclick = function (e) {
    scwin.f_FieldClear();
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.lc_hhEchYn_onviewchange = function (info) {
    scwin.f_changeTime();
};

scwin.btn_Add_onclick = function (e) {
    scwin.f_AddRow();
};

scwin.btn_Update_onclick = function (e) {
    scwin.f_Modify();
};

scwin.btn_Save_onclick = function (e) {
    scwin.f_Save();
};

scwin.sbm_save_submitdone = function (e) {
    console.log(e.responseJSON.resultDataSet);
    if(e.responseJSON.resultDataSet[0].Code == 0) {
        scwin.rowFlag = "";  // 초기화
        $c.win.alert(MSG_CM_INF_001); // 성공적으로 저장하였습니다
    } else {
        if(e.responseJSON.resultDataSet[1] != null && e.responseJSON.resultDataSet[1].Msg != null && e.responseJSON.resultDataSet[1].Msg != "") {
            $c.win.alert(e.responseJSON.resultDataSet[1].Msg);
        }
    }
};

scwin.sbm_retrieve_submitdone = function (e) {
    var rowcnt = ds_retrieveResult.getRowCount();

    for(var i = 0; i < rowcnt; i++){
        ds_retrieveResult.setCellData(i, "extdStHh2", ds_retrieveResult.getCellData(i, "extdStHh"));
        ds_retrieveResult.setCellData(i, "midngtStHh2", ds_retrieveResult.getCellData(i, "midngtStHh"));
        ds_retrieveResult.setCellData(i, "saturdayExtdStHh2", ds_retrieveResult.getCellData(i, "saturdayExtdStHh"));
        ds_retrieveResult.setCellData(i, "saturdayMidngtStHh2", ds_retrieveResult.getCellData(i, "saturdayMidngtStHh"));
    }
    ds_retrieveResult.reform();
    //ds_retrieveResult.modifyAllStatus("R");

    //ds_retrieveResult.setRowPosition(0);
    gr_retrieveResult.setFocusedCell(0,0);
    scwin.f_OnLoadCompleted(rowcnt);
    spa_cnt.setValue(rowcnt);
    if ( rowcnt == 0 ) {
        $c.win.alert(MSG_CM_WRN_002);
    }
};

scwin.gr_retrieveResult_onrowindexchange = function (rowIndex, oldRow) {
    scwin.f_RowChange();
};

scwin.lc_extdStHhSel_onviewchange = function (info) {
    lc_extdStHh.setSelectedIndex(lc_extdStHhSel.getSelectedIndex());
};

scwin.lc_extdStHhSel_onselected = function () {
    lc_midngtStHhSel.setSelectedIndex(lc_extdStHhSel.getSelectedIndex()+1);

    var row = ds_retrieveResult.getRowPosition();
    if(row > 0 ) {
        ds_retrieveResult.setCellData(row,"extdStHh", 	lc_extdStHhSel.getValue());
    }  
};

scwin.lc_midngtStHhSel_onselected = function () {
    var check = lc_midngtStHhSel.getSelectedIndex();
    if(check <= 0 ) {
        $c.win.alert(" 선택 할수 없는 시간 입니다.");
        lc_midngtStHhSel.setSelectedIndex(lc_extdStHhSel.getSelectedIndex()+1);
        return;
    }
    lc_extdStHhSel.setSelectedIndex(lc_midngtStHhSel.getSelectedIndex()-1);

    var row = ds_retrieveResult.getRowPosition();
    if(row > 0 ) {
        ds_retrieveResult.setCellData(row,"midngtStHh", 	lc_midngtStHhSel.getValue());
    }  
};

